LEGACY_HTML = True  # 既存HTMLを保持（再アセンブル禁止）
TITLE = '賃貸vs購入コスト比較 - 生涯コストを無料シミュレーション'
DESCRIPTION = '年齢・年収・家族構成から賃貸と住宅購入の生涯コストを比較。ローン返済・管理費・売却想定価格を含めた総合判断を無料で診断します。'
JS_CODE = 'function calculate(){\n  var age=parseInt(document.getElementById(\'age\').value);\n  var income=parseInt(document.getElementById(\'income\').value);\n  var rent=parseInt(document.getElementById(\'rent\').value);\n  var price=parseInt(document.getElementById(\'price\').value);\n  var rate=parseFloat(document.getElementById(\'rate\').value)/100/12;\n  var period=parseInt(document.getElementById(\'period\').value);\n  var family=document.getElementById(\'family\').value;\n\n  // 賃貸コスト（毎年1%家賃上昇想定）\n  var rentTotal=0;\n  var r=rent*10000;\n  for(var i=0;i<period;i++){rentTotal+=r*12;r*=1.01;}\n\n  // 購入コスト\n  var loanAmt=price*10000*0.9; // 90%ローン\n  var n=35*12; // 35年ローン\n  var monthlyPay=rate===0?loanAmt/n:loanAmt*rate*Math.pow(1+rate,n)/(Math.pow(1+rate,n)-1);\n  var totalLoanCost=monthlyPay*n;\n  var maintenanceCost=period*30*10000; // 管理費・修繕積立・固定資産税 年30万\n  var downpay=price*10000*0.1;\n  var misc=price*10000*0.04;\n  var sellVal=price*10000*Math.pow(0.99,period); // 1%/年 資産価値下落想定\n\n  // 実質購入コスト = 頭金 + 諸費用 + ローン利息分 + 管理費 - 売却益\n  var interestTotal=totalLoanCost-loanAmt;\n  var buyCost=downpay+misc+interestTotal+maintenanceCost;\n  var netBuyCost=buyCost-(sellVal-loanAmt*0.5>0?sellVal-loanAmt*0.5:0); // 残債考慮\n\n  document.getElementById(\'r-period\').textContent=period+\'年\';\n  document.getElementById(\'r-rent-total\').textContent=Math.round(rentTotal/10000/100)/10+\'千万円\';\n  document.getElementById(\'r-buy-total\').textContent=Math.round(netBuyCost/10000/100)/10+\'千万円\';\n  document.getElementById(\'r-monthly-pay\').textContent=Math.round(monthlyPay/10000*10)/10+\'万円/月\';\n  document.getElementById(\'r-downpay\').textContent=Math.round(downpay/10000)+\'万円\';\n  document.getElementById(\'r-misc\').textContent=Math.round(misc/10000)+\'万円\';\n\n  var diff=rentTotal-netBuyCost;\n  var vl=document.getElementById(\'r-verdict-label\');\n  var vd=document.getElementById(\'r-verdict-desc\');\n  if(diff>0){\n    vl.innerHTML=\'✅ <span style="color:#16a34a">購入の方がお得（\'+Math.round(diff/10000/100)/10+\'千万円安い）</span>\';\n    vd.textContent=period+\'年間の比較では、購入の方がトータルコストを抑えられる見込みです。ただし頭金や諸費用の初期負担にご注意ください。\';\n  } else {\n    vl.innerHTML=\'🏠 <span style="color:#2563eb">賃貸の方がコスト効率が良い（\'+Math.round(-diff/10000/100)/10+\'千万円安い）</span>\';\n    vd.textContent=\'居住期間\'+period+\'年では、賃貸の方がトータルコストが低い計算になります。ライフスタイルや転勤可能性も考慮して判断しましょう。\';\n  }\n\n  var advices=[];\n  if(income<500)advices.push({icon:\'⚠️\',text:\'年収からみると月々ローン返済（\'+Math.round(monthlyPay/10000*10)/10+\'万円）は年収の\'+Math.round(monthlyPay*12/income/10000*100)+\'%です。25%以下が安心ライン。\'});\n  if(family===\'single\')advices.push({icon:\'🎯\',text:\'転勤・転職の可能性がある場合、賃貸の柔軟性が大きなメリット。購入後は売却に2〜3年かかる場合も。\'});\n  if(family===\'family\')advices.push({icon:\'👶\',text:\'子育て期に自分の持ち家があると安定感が増します。学区・環境も含めた長期目線で検討を。\'});\n  if(period<15)advices.push({icon:\'📅\',text:\'15年未満の居住では売却損が出やすい。短期なら賃貸が有利なケースが多いです。\'});\n  advices.push({icon:\'💰\',text:\'住宅ローン控除（13年間・最大455万円）や住宅取得等資金の非課税制度を活用すると実質コストがさらに下がります。\'});\n\n  var al=document.getElementById(\'r-advice-list\');al.innerHTML=\'\';\n  advices.forEach(function(a){\n    var d=document.createElement(\'div\');\n    d.className=\'flex gap-2 text-sm bg-blue-50 rounded-lg p-3\';\n    d.innerHTML=\'<span class="flex-shrink-0">\'+a.icon+\'</span><span class="text-gray-700">\'+a.text+\'</span>\';\n    al.appendChild(d);\n  });\n\n  document.getElementById(\'results\').style.display=\'block\';\n  document.getElementById(\'results\').scrollIntoView({behavior:\'smooth\'});\n}\nfunction reset(){document.getElementById(\'results\').style.display=\'none\';window.scrollTo({top:0,behavior:\'smooth\'});}'
